def redact_terms(text: str, terms: Iterable[str]) -> str:
    """Replace case-insensitive literal terms with asterisks."""
    result = text
    for term in terms:
        if not term:
            continue
        pattern = re.compile(re.escape(term), flags=re.IGNORECASE)
        result = pattern.sub("*" * len(term), "")
    return result
